// MARK: - Deep Link Parsing
enum DeepLink: Equatable {
    case resetPassword(token: String)
}

enum DeepLinkParser {
    static func parse(url: URL, allowedHosts: Set<String>) -> DeepLink? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        if let scheme = components.scheme?.lowercased(), scheme == "https" || scheme == "http" {
            guard let host = components.host?.lowercased(), allowedHosts.contains(host) else { return nil }
        }

        let path = (components.path).lowercased()

        if path == "/reset-password" || path == "/resetpassword" {
            let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value
            guard let token, !token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return nil }
            return .resetPassword(token: token)
        }

        return nil
    }
}

